drop table hospedagem;
drop table reserva;
drop table cliente;
drop table quarto;
drop table tipo;

create table tipo (
	codigo integer not null,
	nome varchar(100) not null,
	valor real,
	primary key (codigo)
);

create table quarto (
	codigo integer not null,
	andar integer not null,
	quarto integer not null,
	camassolteiro integer not null,
	camascasal integer not null,
	tipo integer not null,
	foreign key (tipo) references tipo(codigo),
	primary key (codigo)
);

create table cliente (
	cpf char(11) not null,
	nome varchar(100) not null,
	telefone varchar(20) not null,
	logradouro varchar(100),
	numero varchar(10),
	bairro varchar(100),
	cep char(8),
	cidade varchar(100),
	uf char(2),
	pais varchar(100),
	primary key(cpf)
);

create table reserva (
	codigo integer not null,
	inicio date not null,
	fim date not null,
	qtdepessoas integer not null,
	tipo integer not null,
	cliente char(11) not null,
	foreign key (tipo) references tipo(codigo),
	foreign key (cliente) references cliente(cpf),
	primary key (codigo)
);

create table hospedagem (
	codigo integer not null,
	entrada date not null,
	saida date,
	qtdepessoas integer not null,
	quarto integer not null,
	cliente char(11) not null,
	foreign key (quarto) references quarto(codigo),
	foreign key (cliente) references cliente(cpf),
	primary key (codigo)
);






